def pipeline_pressure_spread(n, readings, operations):
    if n == 0:
        return []

    tree_min = [0] * (4 * n)
    tree_max = [0] * (4 * n)
    lazy = [0] * (4 * n)

    def build(node, start, end):
        if start == end:
            tree_min[node] = readings[start]
            tree_max[node] = readings[start]
            return
        mid = (start + end) // 2
        build(2 * node, start, mid)
        build(2 * node + 1, mid + 1, end)
        tree_min[node] = min(tree_min[2 * node], tree_min[2 * node + 1])
        tree_max[node] = max(tree_max[2 * node], tree_max[2 * node + 1])

    def push_down(node):
        if lazy[node] != 0:
            for child in [2 * node, 2 * node + 1]:
                tree_min[child] += lazy[node]
                tree_max[child] += lazy[node]
                lazy[child] += lazy[node]
            lazy[node] = 0

    def range_add(node, start, end, l, r, val):
        if r < start or end < l:
            return
        if l <= start and end <= r:
            tree_min[node] += val
            tree_max[node] += val
            lazy[node] += val
            return
        push_down(node)
        mid = (start + end) // 2
        range_add(2 * node, start, mid, l, r, val)
        range_add(2 * node + 1, mid + 1, end, l, r, val)
        tree_min[node] = min(tree_min[2 * node], tree_min[2 * node + 1])
        tree_max[node] = max(tree_max[2 * node], tree_max[2 * node + 1])

    def query(node, start, end, l, r):
        if r < start or end < l:
            return (float('inf'), float('-inf'))
        if l <= start and end <= r:
            return (tree_min[node], tree_max[node])
        push_down(node)
        mid = (start + end) // 2
        lmin, lmax = query(2 * node, start, mid, l, r)
        rmin, rmax = query(2 * node + 1, mid + 1, end, l, r)
        return (min(lmin, rmin), max(lmax, rmax))

    build(1, 0, n - 1)

    results = []
    for op in operations:
        if op[0] == "add":
            _, l, r, val = op
            range_add(1, 0, n - 1, l, r, val)
        elif op[0] == "spread":
            _, l, r = op
            mn, mx = query(1, 0, n - 1, l, r)
            results.append(mx - mn)

    return results

