import unittest

class TestSolution(unittest.TestCase):

    def test_basic_example(self):
        result = pipeline_pressure_spread(
            5, [10, 20, 30, 40, 50],
            [("spread", 0, 4), ("add", 1, 3, 5), ("spread", 0, 4), ("spread", 1, 3)]
        )
        self.assertEqual(result, [40, 40, 20])

    def test_all_same_values(self):
        result = pipeline_pressure_spread(
            3, [7, 7, 7],
            [("spread", 0, 2), ("add", 1, 1, 3), ("spread", 0, 2)]
        )
        self.assertEqual(result, [0, 3])

    def test_mixed_operations(self):
        result = pipeline_pressure_spread(
            6, [1, 5, 3, 8, 2, 7],
            [("spread", 0, 5), ("add", 2, 4, 10), ("spread", 0, 5),
             ("spread", 2, 4), ("add", 0, 5, -5), ("spread", 0, 5)]
        )
        self.assertEqual(result, [7, 17, 6, 17])

    def test_hidden_single_element(self):
        result = pipeline_pressure_spread(
            1, [42],
            [("spread", 0, 0), ("add", 0, 0, 100), ("spread", 0, 0)]
        )
        self.assertEqual(result, [0, 0])

    def test_hidden_negative_values(self):
        result = pipeline_pressure_spread(
            5, [-10, -5, 0, 5, 10],
            [("spread", 0, 4), ("add", 0, 2, -15), ("spread", 0, 4), ("spread", 0, 2)]
        )
        self.assertEqual(result, [20, 35, 10])

    def test_hidden_no_operations(self):
        result = pipeline_pressure_spread(3, [1, 2, 3], [])
        self.assertEqual(result, [])

    def test_hidden_only_adds(self):
        result = pipeline_pressure_spread(
            3, [1, 2, 3],
            [("add", 0, 2, 5)]
        )
        self.assertEqual(result, [])

    def test_hidden_sequential_adds(self):
        result = pipeline_pressure_spread(
            5, [0, 0, 0, 0, 0],
            [("add", 0, 0, 10), ("add", 4, 4, 20), ("add", 1, 3, 5),
             ("spread", 0, 4), ("spread", 1, 3)]
        )
        self.assertEqual(result, [15, 0])

    def test_hidden_point_queries(self):
        result = pipeline_pressure_spread(
            4, [100, 200, 300, 400],
            [("spread", 0, 0), ("spread", 1, 1), ("spread", 2, 3),
             ("add", 2, 3, -100), ("spread", 2, 3), ("spread", 0, 3)]
        )
        self.assertEqual(result, [0, 0, 100, 0, 100])

    def test_hidden_large_values(self):
        result = pipeline_pressure_spread(
            3, [1000000000, -1000000000, 0],
            [("spread", 0, 2), ("add", 0, 0, -1000000000),
             ("add", 1, 1, 1000000000), ("spread", 0, 2)]
        )
        self.assertEqual(result, [2000000000, 0])

if __name__ == '__main__':
    unittest.main()
